// ─── LOGIN SCREEN ─────────────────────────────────────────────────────────────
function LoginScreen({ role, onLogin, onBack, config }) {
  const [user, setUser] = useState('');
  const [pass, setPass] = useState('');
  const [error, setError] = useState(false);
  const [showPass, setShowPass] = useState(false);

  const handleLogin = () => {
    const cred = CREDENCIALES[role];
    const dynPass =
      role === 'cashier'
        ? config?.passCajero || cred.pass
        : config?.passAdmin || cred.pass;
    if (user === cred.user && pass === dynPass) {
      setError(false);
      onLogin();
    } else {
      setError(true);
      setUser('');
      setPass('');
    }
  };

  const icon = role === 'cashier' ? '🖨️' : '⚙️';
  const label = role === 'cashier' ? 'Vista Cajero' : 'Administrador';

  return (
    <div
      style={{
        minHeight: '100vh',
        background: C.bg,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        fontFamily: "'Segoe UI', system-ui, sans-serif",
        padding: 20,
      }}
    >
      <style>{`
        @keyframes slideIn { from { transform: translateY(30px); opacity: 0; } to { transform: translateY(0); opacity: 1; } }
        @keyframes shake { 0%,100%{transform:translateX(0)} 20%{transform:translateX(-8px)} 40%{transform:translateX(8px)} 60%{transform:translateX(-5px)} 80%{transform:translateX(5px)} }
        * { box-sizing: border-box; } input { outline: none; }
      `}</style>
      <div
        style={{
          background: C.card,
          borderRadius: 20,
          padding: '40px 36px',
          width: '100%',
          maxWidth: 380,
          boxShadow: '0 20px 60px rgba(0,0,0,0.6)',
          animation: error ? 'shake 0.4s ease' : 'slideIn 0.4s ease',
          border: `1px solid ${error ? C.red : '#3a3a3a'}`,
        }}
      >
        {/* Logo */}
        <div style={{ textAlign: 'center', marginBottom: 28 }}>
          <img
            src={LOGO_B64}
            alt="Almíbar"
            style={{
              width: 110,
              height: 110,
              objectFit: 'contain',
              margin: '0 auto 10px',
              display: 'block',
            }}
          />
          <div style={{ color: C.gray, fontSize: 14, marginTop: 2 }}>
            {label}
          </div>
        </div>

        {/* Form */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
          <div>
            <label
              style={{
                fontSize: 12,
                color: C.gray,
                display: 'block',
                marginBottom: 6,
                fontWeight: 600,
                letterSpacing: 0.5,
              }}
            >
              USUARIO
            </label>
            <input
              value={user}
              onChange={(e) => {
                setUser(e.target.value);
                setError(false);
              }}
              onKeyDown={(e) => e.key === 'Enter' && handleLogin()}
              placeholder="Ingresa tu usuario"
              style={{
                width: '100%',
                background: C.surface,
                border: `1px solid ${error ? C.red : '#444'}`,
                borderRadius: 10,
                padding: '12px 14px',
                color: C.white,
                fontSize: 15,
                fontFamily: 'inherit',
              }}
            />
          </div>
          <div>
            <label
              style={{
                fontSize: 12,
                color: C.gray,
                display: 'block',
                marginBottom: 6,
                fontWeight: 600,
                letterSpacing: 0.5,
              }}
            >
              CONTRASEÑA
            </label>
            <div style={{ position: 'relative' }}>
              <input
                value={pass}
                onChange={(e) => {
                  setPass(e.target.value);
                  setError(false);
                }}
                onKeyDown={(e) => e.key === 'Enter' && handleLogin()}
                type={showPass ? 'text' : 'password'}
                placeholder="Ingresa tu contraseña"
                style={{
                  width: '100%',
                  background: C.surface,
                  border: `1px solid ${error ? C.red : '#444'}`,
                  borderRadius: 10,
                  padding: '12px 44px 12px 14px',
                  color: C.white,
                  fontSize: 15,
                  fontFamily: 'inherit',
                }}
              />
              <button
                onClick={() => setShowPass(!showPass)}
                style={{
                  position: 'absolute',
                  right: 12,
                  top: '50%',
                  transform: 'translateY(-50%)',
                  background: 'none',
                  border: 'none',
                  color: C.gray,
                  cursor: 'pointer',
                  fontSize: 16,
                }}
              >
                {showPass ? '🙈' : '👁️'}
              </button>
            </div>
          </div>

          {error && (
            <div
              style={{
                background: '#c0392b22',
                border: '1px solid #c0392b55',
                borderRadius: 8,
                padding: '10px 14px',
                color: '#e74c3c',
                fontSize: 13,
                textAlign: 'center',
              }}
            >
              ❌ Usuario o contraseña incorrectos
            </div>
          )}

          <button
            onClick={handleLogin}
            style={{
              background: C.red,
              color: C.white,
              border: 'none',
              borderRadius: 10,
              padding: '14px',
              fontSize: 16,
              fontWeight: 800,
              cursor: 'pointer',
              marginTop: 4,
              fontFamily: 'inherit',
              transition: 'opacity 0.2s',
            }}
          >
            Ingresar →
          </button>

          <button
            onClick={onBack}
            style={{
              background: 'none',
              border: 'none',
              color: C.gray,
              cursor: 'pointer',
              fontSize: 13,
              fontFamily: 'inherit',
              marginTop: 4,
            }}
          >
            ← Volver al menú de clientes
          </button>
        </div>
      </div>
    </div>
  );
}

// ─── APP PRINCIPAL ────────────────────────────────────────────────────────────
export default function App() {
  // Detectar ruta por hash: #caja | #admin | (vacío = cliente)
  const getHashRoute = () => {
    const h = window.location.hash;
    if (h === '#caja') return 'cashier';
    if (h === '#admin') return 'admin';
    return 'customer';
  };

  const [route, setRoute] = useState(getHashRoute);
  const [authCashier, setAuthCashier] = useState(false);
  const [authAdmin, setAuthAdmin] = useState(false);
  const [menu, setMenu] = useState(initialMenu);
  const [orders, setOrders] = useState([]);
  const [config, setConfig] = useState(initialConfig);
  const [cashRegister, setCashRegister] = useState({
    open: false,
    openAmount: 0,
    movements: [],
    closedAt: null,
  });
  const [newOrderFlag, setNewOrderFlag] = useState(false);

  // Escuchar cambios de hash en la URL
  useEffect(() => {
    const onHash = () => setRoute(getHashRoute());
    window.addEventListener('hashchange', onHash);
    return () => window.removeEventListener('hashchange', onHash);
  }, []);

  const navigate = (hash) => {
    window.location.hash = hash;
    setRoute(getHashRoute());
  };

  const addOrder = useCallback((order) => {
    const newOrder = {
      ...order,
      id: Date.now(),
      status: 'pending',
      createdAt: new Date(),
    };
    setOrders((prev) => [newOrder, ...prev]);
    setNewOrderFlag(true);
    playBeep();
  }, []);

  const updateOrderStatus = (id, status) =>
    setOrders((prev) => prev.map((o) => (o.id === id ? { ...o, status } : o)));

  const pendingCount = orders.filter((o) => o.status === 'pending').length;

  const globalStyles = `
    @keyframes pulse   { from{opacity:1} to{opacity:0.2} }
    @keyframes slideIn { from{transform:translateY(20px);opacity:0} to{transform:translateY(0);opacity:1} }
    @keyframes shake   { 0%,100%{transform:translateX(0)} 25%{transform:translateX(-4px)} 75%{transform:translateX(4px)} }
    @keyframes ring    { 0%,100%{transform:rotate(0)} 20%{transform:rotate(-15deg)} 40%{transform:rotate(15deg)} 60%{transform:rotate(-10deg)} 80%{transform:rotate(10deg)} }
    * { box-sizing: border-box; }
    ::-webkit-scrollbar{width:6px} ::-webkit-scrollbar-track{background:#111} ::-webkit-scrollbar-thumb{background:#444;border-radius:3px}
    input,textarea,select{outline:none}
    @media print { body>*{display:none!important} #print-comanda{display:block!important} }
  `;

  // ── VISTA CAJERO ──────────────────────────────────────────────────────────
  if (route === 'cashier') {
    if (!authCashier)
      return (
        <>
          <style>{globalStyles}</style>
          <LoginScreen
            role="cashier"
            onLogin={() => setAuthCashier(true)}
            onBack={() => navigate('')}
            config={config}
          />
        </>
      );
    return (
      <div
        style={{
          minHeight: '100vh',
          background: C.bg,
          fontFamily: "'Segoe UI', system-ui, sans-serif",
          color: C.white,
        }}
      >
        <style>{globalStyles}</style>
        <nav
          style={{
            background: '#111',
            borderBottom: `2px solid ${C.redDark}`,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            padding: '0 16px',
            height: 56,
            position: 'sticky',
            top: 0,
            zIndex: 100,
            boxShadow: '0 2px 12px rgba(0,0,0,0.5)',
          }}
        >
          <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
            <img
              src={LOGO_B64}
              alt="Almíbar"
              style={{ width: 38, height: 38, objectFit: 'contain' }}
            />
            <span style={{ fontWeight: 800, fontSize: 18, letterSpacing: 1 }}>
              ALMí<span style={{ color: C.red }}>BAR</span> — Caja
            </span>
            {pendingCount > 0 && <Badge n={pendingCount} />}
            {newOrderFlag && (
              <span
                style={{
                  animation: 'pulse 0.5s infinite alternate',
                  marginLeft: 4,
                }}
              >
                🔴 Nuevo pedido
              </span>
            )}
          </div>
          <button
            onClick={() => {
              setAuthCashier(false);
              navigate('');
            }}
            style={{
              background: 'none',
              border: `1px solid #444`,
              borderRadius: 8,
              color: C.gray,
              cursor: 'pointer',
              padding: '6px 14px',
              fontSize: 13,
              fontFamily: 'inherit',
            }}
          >
            Cerrar sesión
          </button>
        </nav>
        <CashierView
          orders={orders}
          updateOrderStatus={updateOrderStatus}
          newOrderFlag={newOrderFlag}
          cashRegister={cashRegister}
          setCashRegister={setCashRegister}
          onSeen={() => setNewOrderFlag(false)}
        />
      </div>
    );
  }

  // ── VISTA ADMIN ───────────────────────────────────────────────────────────
  if (route === 'admin') {
    if (!authAdmin)
      return (
        <>
          <style>{globalStyles}</style>
          <LoginScreen
            role="admin"
            onLogin={() => setAuthAdmin(true)}
            onBack={() => navigate('')}
            config={config}
          />
        </>
      );
    return (
      <div
        style={{
          minHeight: '100vh',
          background: C.bg,
          fontFamily: "'Segoe UI', system-ui, sans-serif",
          color: C.white,
        }}
      >
        <style>{globalStyles}</style>
        <nav
          style={{
            background: '#111',
            borderBottom: `2px solid ${C.redDark}`,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            padding: '0 16px',
            height: 56,
            position: 'sticky',
            top: 0,
            zIndex: 100,
            boxShadow: '0 2px 12px rgba(0,0,0,0.5)',
          }}
        >
          <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
            <img
              src={LOGO_B64}
              alt="Almíbar"
              style={{ width: 38, height: 38, objectFit: 'contain' }}
            />
            <span style={{ fontWeight: 800, fontSize: 18, letterSpacing: 1 }}>
              ALMí<span style={{ color: C.red }}>BAR</span> — Admin
            </span>
          </div>
          <button
            onClick={() => {
              setAuthAdmin(false);
              navigate('');
            }}
            style={{
              background: 'none',
              border: `1px solid #444`,
              borderRadius: 8,
              color: C.gray,
              cursor: 'pointer',
              padding: '6px 14px',
              fontSize: 13,
              fontFamily: 'inherit',
            }}
          >
            Cerrar sesión
          </button>
        </nav>
        <AdminView
          menu={menu}
          setMenu={setMenu}
          orders={orders}
          cashRegister={cashRegister}
          setCashRegister={setCashRegister}
          config={config}
          setConfig={setConfig}
        />
      </div>
    );
  }

  // ── VISTA CLIENTE (default) ───────────────────────────────────────────────
  return (
    <div
      style={{
        minHeight: '100vh',
        background: C.bg,
        fontFamily: "'Segoe UI', system-ui, sans-serif",
        color: C.white,
      }}
    >
      <style>{globalStyles}</style>
      {/* NAV LIMPIO SOLO PARA CLIENTES — sin botones de caja ni admin */}
      <nav
        style={{
          background: '#111',
          borderBottom: `2px solid ${C.redDark}`,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          padding: '0 16px',
          height: 56,
          position: 'sticky',
          top: 0,
          zIndex: 100,
          boxShadow: '0 2px 12px rgba(0,0,0,0.5)',
        }}
      >
        <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
          <div
            style={{
              width: 38,
              height: 38,
              borderRadius: '50%',
              background: '#000',
              border: `2px solid ${C.red}`,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: 18,
            }}
          >
            🍕
          </div>
          <span
            style={{
              fontWeight: 800,
              fontSize: 18,
              color: C.white,
              letterSpacing: 1,
            }}
          >
            ALMí<span style={{ color: C.red }}>BAR</span>
          </span>
        </div>
        <div style={{ color: C.gray, fontSize: 13 }}>
          Cocina y Bar — Delivery
        </div>
      </nav>
      <CustomerView menu={menu} addOrder={addOrder} config={config} />
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// VISTA CLIENTE
// ═══════════════════════════════════════════════════════════════════════════════
function CustomerView({ menu, addOrder, config }) {
  const [selCat, setSelCat] = useState('pizzas');
  const [cart, setCart] = useState([]);
  const [step, setStep] = useState('menu'); // menu | cart | checkout | success
  const [form, setForm] = useState({
    name: '',
    phone: '',
    address: '',
    notes: '',
    delivery: 'pickup',
    payment: 'efectivo',
    time: '',
  });
  const [imgModal, setImgModal] = useState(null);

  const activeMenu = menu.filter((p) => p.active);
  const catItems = activeMenu.filter((p) => p.cat === selCat);
  const cartTotal = cart.reduce((s, i) => s + i.price * i.qty, 0);
  const deliveryCost =
    form.delivery === 'delivery' ? config?.deliveryCost ?? 1990 : 0;
  const totalFinal = cartTotal + deliveryCost;
  const cartCount = cart.reduce((s, i) => s + i.qty, 0);

  const addToCart = (item) => {
    setCart((prev) => {
      const ex = prev.find((i) => i.id === item.id);
      if (ex)
        return prev.map((i) =>
          i.id === item.id ? { ...i, qty: i.qty + 1 } : i
        );
      return [...prev, { ...item, qty: 1 }];
    });
  };

  const removeFromCart = (id) =>
    setCart((prev) => {
      const ex = prev.find((i) => i.id === id);
      if (ex.qty === 1) return prev.filter((i) => i.id !== id);
      return prev.map((i) => (i.id === id ? { ...i, qty: i.qty - 1 } : i));
    });

  const removeItem = (id) => setCart((prev) => prev.filter((i) => i.id !== id));

  const buildWAMessage = () => {
    let msg = `🍕 *NUEVO PEDIDO - ALMÍBAR*\n\n`;
    msg += `👤 *Cliente:* ${form.name}\n📞 *Teléfono:* ${form.phone}\n`;
    if (form.delivery === 'delivery')
      msg += `📍 *Dirección:* ${form.address}\n`;
    msg += `🚀 *Tipo:* ${
      form.delivery === 'delivery' ? 'Delivery' : 'Retiro en local'
    }\n`;
    if (form.time) msg += `⏰ *Hora:* ${form.time}\n`;
    msg += `💳 *Pago:* ${form.payment}\n\n`;
    msg += `📋 *DETALLE DEL PEDIDO:*\n`;
    cart.forEach((i) => {
      msg += `  • ${i.qty}x ${i.name} — ${fmt(i.price * i.qty)}\n`;
    });
    msg += `\n🛒 *Subtotal:* ${fmt(cartTotal)}`;
    if (deliveryCost > 0) msg += `\n🚗 *Delivery:* ${fmt(deliveryCost)}`;
    msg += `\n💰 *TOTAL: ${fmt(totalFinal)}*`;
    if (form.notes) msg += `\n\n📝 *Notas:* ${form.notes}`;
    return encodeURIComponent(msg);
  };

  const handleCheckout = () => {
    const order = {
      customerName: form.name,
      phone: form.phone,
      address: form.address,
      notes: form.notes,
      delivery: form.delivery,
      payment: form.payment,
      time: form.time,
      items: cart,
      subtotal: cartTotal,
      deliveryCost,
      total: totalFinal,
    };
    addOrder(order);
    const waUrl = `https://wa.me/${
      config?.whatsapp ?? '56912345678'
    }?text=${buildWAMessage()}`;
    window.open(waUrl, '_blank');
    setCart([]);
    setForm({
      name: '',
      phone: '',
      address: '',
      notes: '',
      delivery: 'pickup',
      payment: 'efectivo',
      time: '',
    });
    setStep('success');
  };

  if (step === 'success')
    return (
      <div
        style={{
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          minHeight: '70vh',
          gap: 20,
          padding: 20,
          animation: 'slideIn 0.4s ease',
        }}
      >
        <div style={{ fontSize: 80 }}>🎉</div>
        <h2 style={{ color: C.green, fontSize: 28, textAlign: 'center' }}>
          ¡Pedido enviado!
        </h2>
        <p style={{ color: C.gray, textAlign: 'center', maxWidth: 340 }}>
          Tu pedido fue enviado a nuestra cocina y al WhatsApp del local. En
          breve recibirás confirmación.
        </p>
        <Btn onClick={() => setStep('menu')}>Hacer otro pedido</Btn>
      </div>
    );

  if (step === 'checkout')
    return (
      <div style={{ maxWidth: 600, margin: '0 auto', padding: 16 }}>
        <button
          onClick={() => setStep('cart')}
          style={{
            background: 'none',
            border: 'none',
            color: C.gold,
            cursor: 'pointer',
            fontSize: 15,
            marginBottom: 16,
            fontFamily: 'inherit',
          }}
        >
          ← Volver al carrito
        </button>
        <h2 style={{ marginBottom: 20, color: C.white }}>Finalizar Pedido</h2>

        <Section title="Datos de contacto">
          <InputField
            label="Nombre completo *"
            value={form.name}
            onChange={(v) => setForm((f) => ({ ...f, name: v }))}
            placeholder="Tu nombre"
          />
          <InputField
            label="Teléfono *"
            value={form.phone}
            onChange={(v) => setForm((f) => ({ ...f, phone: v }))}
            placeholder="+56 9 XXXX XXXX"
            type="tel"
          />
        </Section>

        <Section title="Tipo de entrega">
          <div
            style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10 }}
          >
            {[
              {
                val: 'pickup',
                label: '🏃 Retiro en local',
                sub: 'Sin costo adicional',
              },
              {
                val: 'delivery',
                label: '🚗 Delivery',
                sub: `+${fmt(config?.deliveryCost ?? 1990)}`,
              },
            ].map((opt) => (
              <div
                key={opt.val}
                onClick={() => setForm((f) => ({ ...f, delivery: opt.val }))}
                style={{
                  padding: 14,
                  borderRadius: 10,
                  cursor: 'pointer',
                  transition: 'all 0.2s',
                  background: form.delivery === opt.val ? C.redDark : C.surface,
                  border: `2px solid ${
                    form.delivery === opt.val ? C.red : '#444'
                  }`,
                  textAlign: 'center',
                }}
              >
                <div style={{ fontSize: 20 }}>{opt.label.split(' ')[0]}</div>
                <div style={{ fontWeight: 700, fontSize: 13, marginTop: 4 }}>
                  {opt.label.slice(2)}
                </div>
                <div style={{ color: C.gold, fontSize: 12 }}>{opt.sub}</div>
              </div>
            ))}
          </div>
          {form.delivery === 'delivery' && (
            <InputField
              label="Dirección de entrega *"
              value={form.address}
              onChange={(v) => setForm((f) => ({ ...f, address: v }))}
              placeholder="Calle, número, referencia"
              style={{ marginTop: 10 }}
            />
          )}
          <InputField
            label="Hora de retiro/entrega (opcional)"
            value={form.time}
            onChange={(v) => setForm((f) => ({ ...f, time: v }))}
            placeholder="ej: 20:30"
            style={{ marginTop: 10 }}
          />
        </Section>

        <Section title="Método de pago">
          <div
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(3,1fr)',
              gap: 8,
            }}
          >
            {[
              { val: 'efectivo', label: '💵', sub: 'Efectivo' },
              { val: 'transferencia', label: '🏦', sub: 'Transferencia' },
              { val: 'link_pago', label: '🔗', sub: 'Link de Pago' },
            ].map((opt) => (
              <div
                key={opt.val}
                onClick={() => setForm((f) => ({ ...f, payment: opt.val }))}
                style={{
                  padding: 12,
                  borderRadius: 10,
                  cursor: 'pointer',
                  textAlign: 'center',
                  background: form.payment === opt.val ? C.redDark : C.surface,
                  border: `2px solid ${
                    form.payment === opt.val ? C.red : '#444'
                  }`,
                  transition: 'all 0.2s',
                }}
              >
                <div style={{ fontSize: 24 }}>{opt.label}</div>
                <div style={{ fontSize: 12, fontWeight: 700, marginTop: 4 }}>
                  {opt.sub}
                </div>
              </div>
            ))}
          </div>
          {form.payment === 'transferencia' && (
            <div
              style={{
                marginTop: 10,
                padding: 12,
                background: '#1a2a1a',
                borderRadius: 8,
                border: '1px solid #2a5a2a',
                fontSize: 13,
              }}
            >
              <div style={{ color: C.green, fontWeight: 700 }}>
                Datos bancarios:
              </div>
              <div style={{ color: C.gray, marginTop: 4 }}>
                Banco: {config?.bankName}
              </div>
              <div style={{ color: C.gray }}>Cuenta: {config?.bankAccount}</div>
              <div style={{ color: C.gray }}>RUT: {config?.bankRut}</div>
              <div style={{ color: C.gray }}>Nombre: {config?.bankOwner}</div>
            </div>
          )}
          {form.payment === 'link_pago' && (
            <div
              style={{
                marginTop: 10,
                padding: 12,
                background: '#1a1a2a',
                borderRadius: 8,
                border: '1px solid #2a2a5a',
                fontSize: 13,
              }}
            >
              <div style={{ color: C.blue, fontWeight: 700 }}>
                Se enviará un link de pago a tu WhatsApp al confirmar el pedido.
              </div>
            </div>
          )}
        </Section>

        <Section title="Notas del pedido">
          <textarea
            value={form.notes}
            onChange={(e) => setForm((f) => ({ ...f, notes: e.target.value }))}
            placeholder="Alergias, ingredientes a omitir, instrucciones especiales..."
            style={{
              width: '100%',
              background: C.surface,
              border: '1px solid #444',
              borderRadius: 8,
              color: C.white,
              padding: 10,
              fontSize: 14,
              resize: 'vertical',
              minHeight: 70,
              fontFamily: 'inherit',
            }}
          />
        </Section>

        {/* Resumen */}
        <div
          style={{
            background: C.surface,
            borderRadius: 12,
            padding: 16,
            marginBottom: 20,
          }}
        >
          <div style={{ fontWeight: 700, marginBottom: 10, color: C.gold }}>
            Resumen del pedido
          </div>
          {cart.map((i) => (
            <div
              key={i.id}
              style={{
                display: 'flex',
                justifyContent: 'space-between',
                fontSize: 13,
                color: C.gray,
                marginBottom: 4,
              }}
            >
              <span>
                {i.qty}x {i.name}
              </span>
              <span>{fmt(i.price * i.qty)}</span>
            </div>
          ))}
          <div
            style={{
              borderTop: '1px solid #444',
              marginTop: 10,
              paddingTop: 10,
            }}
          >
            <div
              style={{
                display: 'flex',
                justifyContent: 'space-between',
                fontSize: 13,
                color: C.gray,
              }}
            >
              <span>Subtotal</span>
              <span>{fmt(cartTotal)}</span>
            </div>
            {deliveryCost > 0 && (
              <div
                style={{
                  display: 'flex',
                  justifyContent: 'space-between',
                  fontSize: 13,
                  color: C.gray,
                  marginTop: 4,
                }}
              >
                <span>Delivery</span>
                <span>{fmt(deliveryCost)}</span>
              </div>
            )}
            <div
              style={{
                display: 'flex',
                justifyContent: 'space-between',
                fontSize: 20,
                fontWeight: 800,
                marginTop: 10,
                color: C.white,
              }}
            >
              <span>Total</span>
              <span style={{ color: C.gold }}>{fmt(totalFinal)}</span>
            </div>
          </div>
        </div>

        <Btn
          onClick={handleCheckout}
          disabled={
            !form.name ||
            !form.phone ||
            (form.delivery === 'delivery' && !form.address)
          }
          style={{ width: '100%', padding: '14px 0', fontSize: 16 }}
        >
          📤 Confirmar y enviar pedido
        </Btn>
      </div>
    );

  if (step === 'cart')
    return (
      <div style={{ maxWidth: 600, margin: '0 auto', padding: 16 }}>
        <button
          onClick={() => setStep('menu')}
          style={{
            background: 'none',
            border: 'none',
            color: C.gold,
            cursor: 'pointer',
            fontSize: 15,
            marginBottom: 16,
            fontFamily: 'inherit',
          }}
        >
          ← Seguir comprando
        </button>
        <h2 style={{ marginBottom: 20 }}>🛒 Tu carrito</h2>
        {cart.length === 0 ? (
          <div style={{ textAlign: 'center', padding: 40, color: C.gray }}>
            <div style={{ fontSize: 60 }}>🛒</div>
            <p>Tu carrito está vacío</p>
            <Btn onClick={() => setStep('menu')}>Ver menú</Btn>
          </div>
        ) : (
          <>
            {cart.map((item) => (
              <div
                key={item.id}
                style={{
                  display: 'flex',
                  gap: 12,
                  background: C.card,
                  borderRadius: 12,
                  padding: 12,
                  marginBottom: 10,
                  animation: 'slideIn 0.3s ease',
                }}
              >
                <img
                  src={item.img}
                  alt={item.name}
                  style={{
                    width: 70,
                    height: 70,
                    borderRadius: 8,
                    objectFit: 'cover',
                  }}
                />
                <div style={{ flex: 1 }}>
                  <div style={{ fontWeight: 700, fontSize: 15 }}>
                    {item.name}
                  </div>
                  <div style={{ color: C.gold, fontWeight: 800, marginTop: 4 }}>
                    {fmt(item.price)}
                  </div>
                  <div
                    style={{
                      display: 'flex',
                      alignItems: 'center',
                      gap: 8,
                      marginTop: 8,
                    }}
                  >
                    <button
                      onClick={() => removeFromCart(item.id)}
                      style={{
                        width: 28,
                        height: 28,
                        borderRadius: '50%',
                        background: C.grayLight,
                        border: 'none',
                        color: C.white,
                        cursor: 'pointer',
                        fontSize: 16,
                        fontWeight: 700,
                      }}
                    >
                      −
                    </button>
                    <span
                      style={{
                        fontWeight: 800,
                        minWidth: 20,
                        textAlign: 'center',
                      }}
                    >
                      {item.qty}
                    </span>
                    <button
                      onClick={() => addToCart(item)}
                      style={{
                        width: 28,
                        height: 28,
                        borderRadius: '50%',
                        background: C.red,
                        border: 'none',
                        color: C.white,
                        cursor: 'pointer',
                        fontSize: 16,
                        fontWeight: 700,
                      }}
                    >
                      +
                    </button>
                    <span
                      style={{
                        color: C.gold,
                        fontWeight: 800,
                        marginLeft: 'auto',
                      }}
                    >
                      {fmt(item.price * item.qty)}
                    </span>
                  </div>
                </div>
                <button
                  onClick={() => removeItem(item.id)}
                  style={{
                    background: 'none',
                    border: 'none',
                    color: C.gray,
                    cursor: 'pointer',
                    fontSize: 18,
                    alignSelf: 'flex-start',
                  }}
                >
                  ✕
                </button>
              </div>
            ))}
            <div
              style={{
                background: C.surface,
                borderRadius: 12,
                padding: 16,
                marginTop: 16,
              }}
            >
              <div
                style={{
                  display: 'flex',
                  justifyContent: 'space-between',
                  fontSize: 20,
                  fontWeight: 800,
                }}
              >
                <span>Subtotal</span>
                <span style={{ color: C.gold }}>{fmt(cartTotal)}</span>
              </div>
              <Btn
                onClick={() => setStep('checkout')}
                style={{
                  width: '100%',
                  marginTop: 14,
                  padding: '14px 0',
                  fontSize: 16,
                }}
              >
                Continuar → Datos de entrega
              </Btn>
            </div>
          </>
        )}
      </div>
    );

  // MENU VIEW
  return (
    <div style={{ maxWidth: 900, margin: '0 auto', padding: '16px 12px 80px' }}>
      {/* Hero */}
      <div
        style={{
          textAlign: 'center',
          padding: '24px 0 16px',
          marginBottom: 20,
        }}
      >
        <img
          src={LOGO_B64}
          alt="Almíbar"
          style={{
            width: 180,
            height: 180,
            objectFit: 'contain',
            marginBottom: 8,
          }}
        />
        <h1
          style={{
            fontSize: 26,
            fontWeight: 900,
            color: C.white,
            margin: '0 0 6px',
          }}
        >
          Menú Delivery
        </h1>
        <div style={{ color: C.gray, fontSize: 13 }}>
          📍 {config?.address || 'Curicó'} · ⏰{' '}
          {config?.hoursWeek || 'Mar–Dom 19:00–00:00'}
        </div>
      </div>

      {/* Categorías */}
      <div
        style={{
          display: 'flex',
          gap: 8,
          overflowX: 'auto',
          paddingBottom: 10,
          marginBottom: 20,
          scrollbarWidth: 'none',
        }}
      >
        {CATS.map((cat) => (
          <button
            key={cat.id}
            onClick={() => setSelCat(cat.id)}
            style={{
              whiteSpace: 'nowrap',
              padding: '8px 16px',
              borderRadius: 20,
              border: `2px solid ${selCat === cat.id ? C.red : '#444'}`,
              background: selCat === cat.id ? C.red : C.surface,
              color: C.white,
              cursor: 'pointer',
              fontSize: 13,
              fontWeight: 700,
              transition: 'all 0.2s',
              fontFamily: 'inherit',
            }}
          >
            {cat.label}
          </button>
        ))}
      </div>

      {/* Grid de productos */}
      <div
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fill, minmax(250px, 1fr))',
          gap: 16,
        }}
      >
        {catItems.map((item) => {
          const inCart = cart.find((i) => i.id === item.id);
          return (
            <div
              key={item.id}
              style={{
                background: C.card,
                borderRadius: 14,
                overflow: 'hidden',
                transition: 'transform 0.2s',
                boxShadow: '0 4px 20px rgba(0,0,0,0.3)',
              }}
              onMouseEnter={(e) =>
                (e.currentTarget.style.transform = 'translateY(-4px)')
              }
              onMouseLeave={(e) =>
                (e.currentTarget.style.transform = 'translateY(0)')
              }
            >
              <div
                style={{ position: 'relative', cursor: 'pointer' }}
                onClick={() => setImgModal(item)}
              >
                <img
                  src={item.img}
                  alt={item.name}
                  style={{ width: '100%', height: 160, objectFit: 'cover' }}
                  onError={(e) => {
                    e.target.src =
                      'https://via.placeholder.com/400x200/2e2e2e/888?text=Sin+imagen';
                  }}
                />
                <div
                  style={{
                    position: 'absolute',
                    top: 8,
                    right: 8,
                    background: 'rgba(0,0,0,0.7)',
                    borderRadius: 6,
                    padding: '2px 8px',
                    fontSize: 12,
                    color: C.gold,
                    fontWeight: 700,
                  }}
                >
                  {fmt(item.price)}
                </div>
                {inCart && (
                  <div
                    style={{
                      position: 'absolute',
                      top: 8,
                      left: 8,
                      background: C.red,
                      borderRadius: '50%',
                      width: 26,
                      height: 26,
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      fontSize: 12,
                      fontWeight: 800,
                    }}
                  >
                    {inCart.qty}
                  </div>
                )}
              </div>
              <div style={{ padding: 12 }}>
                <div style={{ fontWeight: 800, fontSize: 15, marginBottom: 4 }}>
                  {item.name}
                </div>
                <div
                  style={{
                    color: C.gray,
                    fontSize: 12,
                    lineHeight: 1.4,
                    marginBottom: 10,
                    minHeight: 34,
                  }}
                >
                  {item.desc}
                </div>
                <div
                  style={{
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'space-between',
                  }}
                >
                  <span
                    style={{ color: C.gold, fontWeight: 900, fontSize: 17 }}
                  >
                    {fmt(item.price)}
                  </span>
                  {inCart ? (
                    <div
                      style={{ display: 'flex', alignItems: 'center', gap: 6 }}
                    >
                      <button
                        onClick={() => removeFromCart(item.id)}
                        style={{
                          width: 28,
                          height: 28,
                          borderRadius: '50%',
                          background: C.grayLight,
                          border: 'none',
                          color: C.white,
                          cursor: 'pointer',
                          fontWeight: 700,
                        }}
                      >
                        −
                      </button>
                      <span
                        style={{
                          fontWeight: 800,
                          minWidth: 16,
                          textAlign: 'center',
                        }}
                      >
                        {inCart.qty}
                      </span>
                      <button
                        onClick={() => addToCart(item)}
                        style={{
                          width: 28,
                          height: 28,
                          borderRadius: '50%',
                          background: C.red,
                          border: 'none',
                          color: C.white,
                          cursor: 'pointer',
                          fontWeight: 700,
                        }}
                      >
                        +
                      </button>
                    </div>
                  ) : (
                    <button
                      onClick={() => addToCart(item)}
                      style={{
                        background: C.red,
                        color: C.white,
                        border: 'none',
                        borderRadius: 8,
                        padding: '6px 14px',
                        fontSize: 13,
                        fontWeight: 700,
                        cursor: 'pointer',
                        fontFamily: 'inherit',
                      }}
                    >
                      + Agregar
                    </button>
                  )}
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {/* Modal imagen */}
      {imgModal && (
        <div
          onClick={() => setImgModal(null)}
          style={{
            position: 'fixed',
            inset: 0,
            background: 'rgba(0,0,0,0.85)',
            zIndex: 200,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            padding: 20,
          }}
        >
          <div
            onClick={(e) => e.stopPropagation()}
            style={{
              background: C.card,
              borderRadius: 16,
              overflow: 'hidden',
              maxWidth: 460,
              width: '100%',
            }}
          >
            <img
              src={imgModal.img}
              alt={imgModal.name}
              style={{ width: '100%', maxHeight: 280, objectFit: 'cover' }}
            />
            <div style={{ padding: 20 }}>
              <div style={{ fontWeight: 800, fontSize: 20 }}>
                {imgModal.name}
              </div>
              <div style={{ color: C.gray, marginTop: 8, lineHeight: 1.6 }}>
                {imgModal.desc}
              </div>
              <div
                style={{
                  color: C.gold,
                  fontWeight: 900,
                  fontSize: 24,
                  marginTop: 12,
                }}
              >
                {fmt(imgModal.price)}
              </div>
              <div style={{ display: 'flex', gap: 10, marginTop: 16 }}>
                <Btn
                  onClick={() => {
                    addToCart(imgModal);
                    setImgModal(null);
                  }}
                  style={{ flex: 1 }}
                >
                  + Agregar al carrito
                </Btn>
                <Btn onClick={() => setImgModal(null)} color={C.grayLight}>
                  Cerrar
                </Btn>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Cart FAB */}
      {cartCount > 0 && (
        <div
          style={{
            position: 'fixed',
            bottom: 20,
            left: '50%',
            transform: 'translateX(-50%)',
            zIndex: 150,
            animation: 'slideIn 0.3s ease',
          }}
        >
          <button
            onClick={() => setStep('cart')}
            style={{
              background: C.red,
              color: C.white,
              border: 'none',
              borderRadius: 30,
              padding: '14px 28px',
              fontSize: 16,
              fontWeight: 800,
              cursor: 'pointer',
              boxShadow: '0 6px 30px rgba(192,57,43,0.6)',
              display: 'flex',
              alignItems: 'center',
              gap: 10,
              fontFamily: 'inherit',
            }}
          >
            🛒 Ver carrito ({cartCount}) — {fmt(cartTotal)}
          </button>
        </div>
      )}
    </div>
  );
}

