// VISTA CAJA / CAJERO
// ═══════════════════════════════════════════════════════════════════════════════
function CashierView({
  orders,
  updateOrderStatus,
  newOrderFlag,
  cashRegister,
  setCashRegister,
  onSeen,
}) {
  const [filter, setFilter] = useState('all');
  const [printOrder, setPrintOrder] = useState(null);
  const [ringing, setRinging] = useState(false);
  const prevCount = useRef(0);

  const pendingOrders = orders.filter((o) => o.status === 'pending');

  useEffect(() => {
    if (orders.length > prevCount.current) {
      setRinging(true);
      setTimeout(() => setRinging(false), 3000);
    }
    prevCount.current = orders.length;
  }, [orders.length]);

  const filtered =
    filter === 'all' ? orders : orders.filter((o) => o.status === filter);

  const statusColors = {
    pending: '#e67e22',
    preparing: C.blue,
    ready: C.green,
    delivered: C.gray,
    cancelled: C.red,
  };
  const statusLabels = {
    pending: '⏳ Pendiente',
    preparing: '👨‍🍳 En cocina',
    ready: '✅ Listo',
    delivered: '🚗 Entregado',
    cancelled: '❌ Cancelado',
  };

  const handlePrint = (order) => {
    setPrintOrder(order);
    setTimeout(() => window.print(), 300);
  };

  const registerMovement = (type, amount, desc) => {
    const mov = { type, amount: parseFloat(amount), desc, at: new Date() };
    setCashRegister((prev) => ({
      ...prev,
      movements: [...prev.movements, mov],
    }));
  };

  return (
    <div style={{ maxWidth: 900, margin: '0 auto', padding: 16 }}>
      {/* Print hidden comanda */}
      {printOrder && (
        <div
          id="print-comanda"
          style={{
            display: 'none',
            fontFamily: 'monospace',
            fontSize: 13,
            color: '#000',
            width: 280,
          }}
        >
          <div style={{ textAlign: 'center', fontWeight: 700, fontSize: 16 }}>
            ALMÍBAR Cocina y Bar
          </div>
          <div style={{ textAlign: 'center', marginBottom: 8 }}>
            ================================
          </div>
          <div>Pedido #{printOrder.id?.toString().slice(-4)}</div>
          <div>Fecha: {new Date().toLocaleString('es-CL')}</div>
          <div>Cliente: {printOrder.customerName}</div>
          <div>Tel: {printOrder.phone}</div>
          <div>
            Tipo:{' '}
            {printOrder.delivery === 'delivery'
              ? `DELIVERY - ${printOrder.address}`
              : 'RETIRO EN LOCAL'}
          </div>
          {printOrder.time && <div>Hora: {printOrder.time}</div>}
          <div>Pago: {printOrder.payment?.toUpperCase()}</div>
          <div style={{ margin: '8px 0' }}>
            --------------------------------
          </div>
          {printOrder.items?.map((i, idx) => (
            <div key={idx}>
              {i.qty}x {i.name}
              <br /> ${(i.price * i.qty).toLocaleString('es-CL')}
            </div>
          ))}
          <div style={{ margin: '8px 0' }}>
            --------------------------------
          </div>
          <div>Subtotal: ${printOrder.subtotal?.toLocaleString('es-CL')}</div>
          {printOrder.deliveryCost > 0 && (
            <div>
              Delivery: ${printOrder.deliveryCost?.toLocaleString('es-CL')}
            </div>
          )}
          <div style={{ fontWeight: 700, fontSize: 16 }}>
            TOTAL: ${printOrder.total?.toLocaleString('es-CL')}
          </div>
          {printOrder.notes && (
            <>
              <div style={{ margin: '8px 0' }}>
                --------------------------------
              </div>
              <div>NOTAS: {printOrder.notes}</div>
            </>
          )}
          <div style={{ textAlign: 'center', marginTop: 8 }}>
            ================================
          </div>
          <div style={{ textAlign: 'center' }}>
            ¡Gracias por su preferencia!
          </div>
        </div>
      )}

      {/* Header con alerta */}
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          marginBottom: 20,
        }}
      >
        <h2 style={{ margin: 0 }}>
          🖨️ Vista Cajero
          {ringing && (
            <span
              style={{
                marginLeft: 10,
                fontSize: 24,
                display: 'inline-block',
                animation: 'ring 0.5s infinite',
              }}
            >
              🔔
            </span>
          )}
        </h2>
        {pendingOrders.length > 0 && (
          <div
            style={{
              background: '#e67e2233',
              border: `1px solid #e67e22`,
              borderRadius: 8,
              padding: '6px 14px',
              color: '#e67e22',
              fontWeight: 700,
              fontSize: 14,
            }}
          >
            {pendingOrders.length} pendiente
            {pendingOrders.length !== 1 ? 's' : ''}
          </div>
        )}
      </div>

      {/* Filtros */}
      <div
        style={{
          display: 'flex',
          gap: 6,
          overflowX: 'auto',
          marginBottom: 16,
          scrollbarWidth: 'none',
        }}
      >
        {['all', 'pending', 'preparing', 'ready', 'delivered'].map((f) => (
          <button
            key={f}
            onClick={() => setFilter(f)}
            style={{
              whiteSpace: 'nowrap',
              padding: '6px 14px',
              borderRadius: 20,
              border: `2px solid ${filter === f ? C.red : '#444'}`,
              background: filter === f ? C.red : C.surface,
              color: C.white,
              cursor: 'pointer',
              fontSize: 13,
              fontWeight: 700,
              fontFamily: 'inherit',
            }}
          >
            {f === 'all' ? 'Todos' : statusLabels[f]}
          </button>
        ))}
      </div>

      {filtered.length === 0 ? (
        <div style={{ textAlign: 'center', padding: 60, color: C.gray }}>
          <div style={{ fontSize: 60 }}>📋</div>
          <p>
            No hay pedidos{' '}
            {filter !== 'all' ? `con estado "${statusLabels[filter]}"` : 'aún'}
          </p>
        </div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
          {filtered.map((order) => (
            <div
              key={order.id}
              style={{
                background: C.card,
                borderRadius: 14,
                padding: 16,
                border: `2px solid ${
                  order.status === 'pending' ? '#e67e22' : '#333'
                }`,
                animation: 'slideIn 0.3s ease',
              }}
            >
              <div
                style={{
                  display: 'flex',
                  alignItems: 'flex-start',
                  justifyContent: 'space-between',
                  marginBottom: 12,
                  flexWrap: 'wrap',
                  gap: 8,
                }}
              >
                <div>
                  <span style={{ fontWeight: 800, fontSize: 16 }}>
                    #{order.id?.toString().slice(-4)} — {order.customerName}
                  </span>
                  <div style={{ color: C.gray, fontSize: 13 }}>
                    📞 {order.phone} · ⏰{' '}
                    {new Date(order.createdAt).toLocaleTimeString('es-CL', {
                      hour: '2-digit',
                      minute: '2-digit',
                    })}
                  </div>
                  <div style={{ fontSize: 13, marginTop: 2 }}>
                    {order.delivery === 'delivery'
                      ? `🚗 Delivery: ${order.address}`
                      : '🏃 Retiro en local'}
                    {order.time && ` · ⏰ ${order.time}`}
                  </div>
                  <div style={{ fontSize: 13, color: C.gray }}>
                    💳 {order.payment}
                  </div>
                </div>
                <div style={{ textAlign: 'right' }}>
                  <div style={{ color: C.gold, fontWeight: 900, fontSize: 20 }}>
                    {fmt(order.total)}
                  </div>
                  <span
                    style={{
                      background: `${statusColors[order.status]}22`,
                      color: statusColors[order.status],
                      border: `1px solid ${statusColors[order.status]}`,
                      borderRadius: 6,
                      padding: '2px 10px',
                      fontSize: 12,
                      fontWeight: 700,
                    }}
                  >
                    {statusLabels[order.status]}
                  </span>
                </div>
              </div>

              {/* Items */}
              <div
                style={{
                  background: '#1a1a1a',
                  borderRadius: 8,
                  padding: 10,
                  marginBottom: 12,
                }}
              >
                {order.items?.map((i, idx) => (
                  <div
                    key={idx}
                    style={{
                      display: 'flex',
                      justifyContent: 'space-between',
                      fontSize: 14,
                      color: C.gray,
                      padding: '2px 0',
                    }}
                  >
                    <span>
                      <b style={{ color: C.white }}>{i.qty}x</b> {i.name}
                    </span>
                    <span>{fmt(i.price * i.qty)}</span>
                  </div>
                ))}
                {order.notes && (
                  <div style={{ marginTop: 8, color: C.orange, fontSize: 13 }}>
                    📝 {order.notes}
                  </div>
                )}
              </div>

              {/* Acciones */}
              <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
                {order.status === 'pending' && (
                  <>
                    <Btn
                      small
                      onClick={() => updateOrderStatus(order.id, 'preparing')}
                      color={C.blue}
                    >
                      👨‍🍳 En cocina
                    </Btn>
                    <Btn
                      small
                      onClick={() => updateOrderStatus(order.id, 'cancelled')}
                      color={C.grayLight}
                    >
                      ❌ Cancelar
                    </Btn>
                  </>
                )}
                {order.status === 'preparing' && (
                  <Btn
                    small
                    onClick={() => updateOrderStatus(order.id, 'ready')}
                    color={C.green}
                  >
                    ✅ Listo
                  </Btn>
                )}
                {order.status === 'ready' && (
                  <Btn
                    small
                    onClick={() => updateOrderStatus(order.id, 'delivered')}
                    color={C.gray}
                  >
                    🚗 Entregado
                  </Btn>
                )}
                <Btn
                  small
                  onClick={() => handlePrint(order)}
                  color={C.grayLight}
                >
                  🖨️ Imprimir
                </Btn>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Módulo caja rápido */}
      <CashQuickModule
        cashRegister={cashRegister}
        setCashRegister={setCashRegister}
        orders={orders}
      />
    </div>
  );
}

function CashQuickModule({ cashRegister, setCashRegister, orders }) {
  const [show, setShow] = useState(false);
  const deliveredTotal = orders
    .filter((o) => o.status === 'delivered')
    .reduce((s, o) => s + o.total, 0);
  const cashIn = cashRegister.movements
    .filter((m) => m.type === 'in')
    .reduce((s, m) => s + m.amount, 0);
  const cashOut = cashRegister.movements
    .filter((m) => m.type === 'out')
    .reduce((s, m) => s + m.amount, 0);
  const balance = (cashRegister.openAmount || 0) + cashIn - cashOut;

  return (
    <div
      style={{
        marginTop: 24,
        background: C.surface,
        borderRadius: 14,
        overflow: 'hidden',
      }}
    >
      <button
        onClick={() => setShow(!show)}
        style={{
          width: '100%',
          padding: '14px 20px',
          background: 'none',
          border: 'none',
          color: C.white,
          fontWeight: 700,
          fontSize: 16,
          cursor: 'pointer',
          textAlign: 'left',
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          fontFamily: 'inherit',
        }}
      >
        💰 Resumen de Caja {show ? '▲' : '▼'}
      </button>
      {show && (
        <div style={{ padding: '0 20px 20px' }}>
          <div
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(3, 1fr)',
              gap: 10,
              marginBottom: 16,
            }}
          >
            <StatCard
              label="Pedidos entregados"
              value={fmt(deliveredTotal)}
              color={C.green}
            />
            <StatCard
              label="Efectivo en caja"
              value={fmt(balance)}
              color={C.gold}
            />
            <StatCard
              label="Pedidos del día"
              value={orders.filter((o) => o.status === 'delivered').length}
              color={C.blue}
            />
          </div>
        </div>
      )}
    </div>
  );
}

