// VISTA ADMINISTRADOR
// ═══════════════════════════════════════════════════════════════════════════════
function AdminView({
  menu,
  setMenu,
  orders,
  cashRegister,
  setCashRegister,
  config,
  setConfig,
}) {
  const [tab, setTab] = useState('products');

  const tabs = [
    { id: 'products', label: '🍕 Productos' },
    { id: 'cash', label: '💰 Caja' },
    { id: 'stats', label: '📊 Estadísticas' },
    { id: 'settings', label: '⚙️ Configuración' },
  ];

  return (
    <div style={{ maxWidth: 900, margin: '0 auto', padding: 16 }}>
      <div
        style={{
          display: 'flex',
          gap: 8,
          marginBottom: 20,
          overflowX: 'auto',
          scrollbarWidth: 'none',
        }}
      >
        {tabs.map((t) => (
          <button
            key={t.id}
            onClick={() => setTab(t.id)}
            style={{
              whiteSpace: 'nowrap',
              padding: '8px 18px',
              borderRadius: 8,
              border: `2px solid ${tab === t.id ? C.red : '#444'}`,
              background: tab === t.id ? C.red : C.surface,
              color: C.white,
              cursor: 'pointer',
              fontWeight: 700,
              fontSize: 14,
              fontFamily: 'inherit',
            }}
          >
            {t.label}
          </button>
        ))}
      </div>

      {tab === 'products' && <ProductManager menu={menu} setMenu={setMenu} />}
      {tab === 'cash' && (
        <CashRegister
          cashRegister={cashRegister}
          setCashRegister={setCashRegister}
          orders={orders}
        />
      )}
      {tab === 'stats' && <StatsView orders={orders} menu={menu} />}
      {tab === 'settings' && (
        <SettingsView config={config} setConfig={setConfig} />
      )}
    </div>
  );
}

