// CONFIGURACIÓN DEL NEGOCIO
// ═══════════════════════════════════════════════════════════════════════════════
function SettingsView({ config, setConfig }) {
  const [form, setForm] = useState({ ...config });
  const [saved, setSaved] = useState(false);
  const [section, setSection] = useState('negocio');

  const set = (key, val) => setForm((f) => ({ ...f, [key]: val }));

  const handleSave = () => {
    setConfig({
      ...form,
      deliveryCost: parseFloat(form.deliveryCost) || 0,
      minOrderDelivery: parseFloat(form.minOrderDelivery) || 0,
    });
    setSaved(true);
    setTimeout(() => setSaved(false), 2500);
  };

  const sections = [
    { id: 'negocio', label: '🏠 Negocio' },
    { id: 'horarios', label: '⏰ Horarios' },
    { id: 'delivery', label: '🚗 Delivery' },
    { id: 'pagos', label: '💳 Pagos' },
    { id: 'accesos', label: '🔑 Accesos' },
  ];

  return (
    <div>
      {/* Tabs de sección */}
      <div
        style={{
          display: 'flex',
          gap: 8,
          marginBottom: 20,
          overflowX: 'auto',
          scrollbarWidth: 'none',
        }}
      >
        {sections.map((s) => (
          <button
            key={s.id}
            onClick={() => setSection(s.id)}
            style={{
              whiteSpace: 'nowrap',
              padding: '6px 14px',
              borderRadius: 20,
              border: `2px solid ${section === s.id ? C.gold : '#444'}`,
              background: section === s.id ? C.gold + '22' : C.surface,
              color: section === s.id ? C.gold : C.gray,
              cursor: 'pointer',
              fontWeight: 700,
              fontSize: 13,
              fontFamily: 'inherit',
            }}
          >
            {s.label}
          </button>
        ))}
      </div>

      <div style={{ background: C.card, borderRadius: 14, padding: 20 }}>
        {/* NEGOCIO */}
        {section === 'negocio' && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
            <SectionTitle>🏠 Información del negocio</SectionTitle>
            <SettingField
              label="Nombre del negocio"
              value={form.businessName}
              onChange={(v) => set('businessName', v)}
              placeholder="Almíbar Cocina y Bar"
            />
            <SettingField
              label="Tagline / Subtítulo"
              value={form.tagline}
              onChange={(v) => set('tagline', v)}
              placeholder="Delivery Curicó"
            />
            <SettingField
              label="Dirección"
              value={form.address}
              onChange={(v) => set('address', v)}
              placeholder="Calle, número, ciudad"
            />
            <SettingField
              label="Teléfono"
              value={form.phone}
              onChange={(v) => set('phone', v)}
              placeholder="+56 9 XXXX XXXX"
            />
            <SettingField
              label="WhatsApp (solo números, con código de país)"
              value={form.whatsapp}
              onChange={(v) => set('whatsapp', v)}
              placeholder="56912345678"
              type="tel"
              helper="Ej: 56912345678 → los pedidos de clientes llegan a este número"
            />
            <SettingField
              label="Email"
              value={form.email}
              onChange={(v) => set('email', v)}
              placeholder="contacto@almibar.bar"
              type="email"
            />
            <SettingField
              label="Instagram"
              value={form.instagram}
              onChange={(v) => set('instagram', v)}
              placeholder="@almibar.bar"
            />
          </div>
        )}

        {/* HORARIOS */}
        {section === 'horarios' && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
            <SectionTitle>⏰ Horarios de atención</SectionTitle>
            <SettingField
              label="Horario semana (aparece en el menú cliente)"
              value={form.hoursWeek}
              onChange={(v) => set('hoursWeek', v)}
              placeholder="Mar–Vie 19:00–00:00"
            />
            <SettingField
              label="Horario fin de semana"
              value={form.hoursWeekend}
              onChange={(v) => set('hoursWeekend', v)}
              placeholder="Sáb–Dom 18:00–01:00"
            />
            <SettingField
              label="Tiempo estimado de entrega"
              value={form.estimatedTime}
              onChange={(v) => set('estimatedTime', v)}
              placeholder="30–45 min"
            />
          </div>
        )}

        {/* DELIVERY */}
        {section === 'delivery' && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
            <SectionTitle>🚗 Configuración de delivery</SectionTitle>
            <SettingField
              label="Costo de delivery (CLP)"
              value={form.deliveryCost}
              onChange={(v) => set('deliveryCost', v)}
              type="number"
              helper="Este valor se suma al total del pedido cuando el cliente elige delivery"
            />
            <SettingField
              label="Pedido mínimo para delivery (CLP)"
              value={form.minOrderDelivery}
              onChange={(v) => set('minOrderDelivery', v)}
              type="number"
            />
            <SettingField
              label="Zona de delivery"
              value={form.deliveryZone}
              onChange={(v) => set('deliveryZone', v)}
              placeholder="Curicó centro y alrededores"
            />
          </div>
        )}

        {/* PAGOS */}
        {section === 'pagos' && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
            <SectionTitle>💳 Datos bancarios para transferencias</SectionTitle>
            <SettingField
              label="Nombre del banco"
              value={form.bankName}
              onChange={(v) => set('bankName', v)}
              placeholder="Banco Estado"
            />
            <SettingField
              label="Número de cuenta"
              value={form.bankAccount}
              onChange={(v) => set('bankAccount', v)}
              placeholder="123-456-789"
            />
            <SettingField
              label="RUT de la empresa"
              value={form.bankRut}
              onChange={(v) => set('bankRut', v)}
              placeholder="76.XXX.XXX-X"
            />
            <SettingField
              label="Nombre del titular"
              value={form.bankOwner}
              onChange={(v) => set('bankOwner', v)}
              placeholder="Inversiones Alma SpA"
            />
            <div
              style={{
                background: '#1a2a1a',
                borderRadius: 10,
                padding: 14,
                border: '1px solid #2a5a2a',
                fontSize: 13,
              }}
            >
              <div style={{ color: C.green, fontWeight: 700, marginBottom: 8 }}>
                👁️ Vista previa — como lo ve el cliente:
              </div>
              <div style={{ color: C.gray }}>
                Banco: <span style={{ color: C.white }}>{form.bankName}</span>
              </div>
              <div style={{ color: C.gray }}>
                Cuenta:{' '}
                <span style={{ color: C.white }}>{form.bankAccount}</span>
              </div>
              <div style={{ color: C.gray }}>
                RUT: <span style={{ color: C.white }}>{form.bankRut}</span>
              </div>
              <div style={{ color: C.gray }}>
                Nombre: <span style={{ color: C.white }}>{form.bankOwner}</span>
              </div>
            </div>
          </div>
        )}

        {/* ACCESOS */}
        {section === 'accesos' && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
            <SectionTitle>🔑 Credenciales de acceso</SectionTitle>
            <div
              style={{
                background: '#2a1a1a',
                border: '1px solid #5a2a2a',
                borderRadius: 10,
                padding: 14,
                fontSize: 13,
                color: '#e74c3c',
              }}
            >
              ⚠️ Guarda estas contraseñas en un lugar seguro. Son las claves
              para entrar a Caja y Admin.
            </div>
            <div
              style={{
                display: 'grid',
                gridTemplateColumns: '1fr 1fr',
                gap: 16,
              }}
            >
              <div
                style={{ background: C.surface, borderRadius: 12, padding: 16 }}
              >
                <div
                  style={{ color: C.gold, fontWeight: 700, marginBottom: 12 }}
                >
                  🖨️ Acceso Cajero
                </div>
                <div style={{ fontSize: 13, color: C.gray, marginBottom: 4 }}>
                  URL: <span style={{ color: C.white }}>tu-url.app/#caja</span>
                </div>
                <div style={{ fontSize: 13, color: C.gray }}>
                  Usuario: <span style={{ color: C.white }}>cajero</span>
                </div>
                <div style={{ marginTop: 12 }}>
                  <SettingField
                    label="Contraseña cajero"
                    value={form.passCajero}
                    onChange={(v) => set('passCajero', v)}
                    type="password"
                    placeholder="Nueva contraseña"
                  />
                </div>
              </div>
              <div
                style={{ background: C.surface, borderRadius: 12, padding: 16 }}
              >
                <div
                  style={{ color: C.gold, fontWeight: 700, marginBottom: 12 }}
                >
                  ⚙️ Acceso Admin
                </div>
                <div style={{ fontSize: 13, color: C.gray, marginBottom: 4 }}>
                  URL: <span style={{ color: C.white }}>tu-url.app/#admin</span>
                </div>
                <div style={{ fontSize: 13, color: C.gray }}>
                  Usuario: <span style={{ color: C.white }}>admin</span>
                </div>
                <div style={{ marginTop: 12 }}>
                  <SettingField
                    label="Contraseña admin"
                    value={form.passAdmin}
                    onChange={(v) => set('passAdmin', v)}
                    type="password"
                    placeholder="Nueva contraseña"
                  />
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Botón guardar */}
        <div
          style={{
            marginTop: 24,
            display: 'flex',
            alignItems: 'center',
            gap: 14,
          }}
        >
          <button
            onClick={handleSave}
            style={{
              background: saved ? C.green : C.red,
              color: C.white,
              border: 'none',
              borderRadius: 10,
              padding: '12px 28px',
              fontSize: 15,
              fontWeight: 800,
              cursor: 'pointer',
              fontFamily: 'inherit',
              transition: 'background 0.3s',
            }}
          >
            {saved ? '✅ ¡Guardado!' : '💾 Guardar cambios'}
          </button>
          {saved && (
            <span style={{ color: C.green, fontSize: 14, fontWeight: 600 }}>
              Los cambios ya están activos en el menú de clientes.
            </span>
          )}
        </div>
      </div>
    </div>
  );
}

function SectionTitle({ children }) {
  return (
    <div
      style={{
        fontWeight: 800,
        fontSize: 17,
        color: C.gold,
        paddingBottom: 8,
        borderBottom: '1px solid #3a3a3a',
        marginBottom: 4,
      }}
    >
      {children}
    </div>
  );
}

function SettingField({
  label,
  value,
  onChange,
  placeholder,
  type = 'text',
  helper,
}) {
  return (
    <div>
      <label
        style={{
          fontSize: 13,
          color: C.gray,
          display: 'block',
          marginBottom: 5,
          fontWeight: 600,
        }}
      >
        {label}
      </label>
      <input
        type={type}
        value={value || ''}
        onChange={(e) => onChange(e.target.value)}
        placeholder={placeholder}
        style={{
          width: '100%',
          background: C.surface,
          border: '1px solid #444',
          borderRadius: 8,
          padding: '10px 12px',
          color: C.white,
          fontSize: 14,
          fontFamily: 'inherit',
        }}
      />
      {helper && (
        <div
          style={{ fontSize: 12, color: C.gray, marginTop: 5, lineHeight: 1.4 }}
        >
          ℹ️ {helper}
        </div>
      )}
    </div>
  );
}

function ProductManager({ menu, setMenu }) {
  const [editing, setEditing] = useState(null);
  const [form, setForm] = useState({});
  const [filterCat, setFilterCat] = useState('all');
  const [search, setSearch] = useState('');
  const [showForm, setShowForm] = useState(false);

  const openNew = () => {
    setForm({
      cat: 'pizzas',
      name: '',
      desc: '',
      price: '',
      img: '',
      active: true,
    });
    setEditing(null);
    setShowForm(true);
  };

  const openEdit = (p) => {
    setForm({ ...p });
    setEditing(p.id);
    setShowForm(true);
  };

  const saveProduct = () => {
    if (!form.name || !form.price) return;
    if (editing) {
      setMenu((prev) =>
        prev.map((p) =>
          p.id === editing
            ? { ...form, id: editing, price: parseFloat(form.price) }
            : p
        )
      );
    } else {
      setMenu((prev) => [
        ...prev,
        {
          ...form,
          id: Date.now(),
          price: parseFloat(form.price),
          active: true,
        },
      ]);
    }
    setShowForm(false);
    setEditing(null);
  };

  const toggleActive = (id) =>
    setMenu((prev) =>
      prev.map((p) => (p.id === id ? { ...p, active: !p.active } : p))
    );
  const deleteProduct = (id) => {
    if (confirm('¿Eliminar este producto?'))
      setMenu((prev) => prev.filter((p) => p.id !== id));
  };

  const filtered = menu.filter(
    (p) =>
      (filterCat === 'all' || p.cat === filterCat) &&
      (p.name.toLowerCase().includes(search.toLowerCase()) ||
        p.desc.toLowerCase().includes(search.toLowerCase()))
  );

  return (
    <div>
      <div
        style={{ display: 'flex', gap: 10, marginBottom: 16, flexWrap: 'wrap' }}
      >
        <input
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          placeholder="🔍 Buscar producto..."
          style={{
            flex: 1,
            minWidth: 180,
            background: C.surface,
            border: '1px solid #444',
            borderRadius: 8,
            padding: '8px 12px',
            color: C.white,
            fontSize: 14,
            fontFamily: 'inherit',
          }}
        />
        <select
          value={filterCat}
          onChange={(e) => setFilterCat(e.target.value)}
          style={{
            background: C.surface,
            border: '1px solid #444',
            borderRadius: 8,
            padding: '8px 12px',
            color: C.white,
            fontSize: 14,
            fontFamily: 'inherit',
          }}
        >
          <option value="all">Todas las categorías</option>
          {CATS.map((c) => (
            <option key={c.id} value={c.id}>
              {c.label}
            </option>
          ))}
        </select>
        <Btn onClick={openNew} color={C.green}>
          + Nuevo producto
        </Btn>
      </div>

      {/* Modal form */}
      {showForm && (
        <div
          style={{
            position: 'fixed',
            inset: 0,
            background: 'rgba(0,0,0,0.85)',
            zIndex: 200,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            padding: 20,
          }}
        >
          <div
            style={{
              background: C.card,
              borderRadius: 16,
              padding: 24,
              width: '100%',
              maxWidth: 480,
              maxHeight: '90vh',
              overflowY: 'auto',
            }}
          >
            <h3 style={{ marginTop: 0, marginBottom: 20 }}>
              {editing ? '✏️ Editar producto' : '➕ Nuevo producto'}
            </h3>
            <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
              <div>
                <label
                  style={{
                    fontSize: 13,
                    color: C.gray,
                    display: 'block',
                    marginBottom: 4,
                  }}
                >
                  Categoría
                </label>
                <select
                  value={form.cat || 'pizzas'}
                  onChange={(e) =>
                    setForm((f) => ({ ...f, cat: e.target.value }))
                  }
                  style={{
                    width: '100%',
                    background: C.surface,
                    border: '1px solid #444',
                    borderRadius: 8,
                    padding: '9px 12px',
                    color: C.white,
                    fontSize: 14,
                    fontFamily: 'inherit',
                  }}
                >
                  {CATS.map((c) => (
                    <option key={c.id} value={c.id}>
                      {c.label}
                    </option>
                  ))}
                </select>
              </div>
              <InputField
                label="Nombre del producto *"
                value={form.name || ''}
                onChange={(v) => setForm((f) => ({ ...f, name: v }))}
                placeholder="ej: Pizza Margherita"
              />
              <div>
                <label
                  style={{
                    fontSize: 13,
                    color: C.gray,
                    display: 'block',
                    marginBottom: 4,
                  }}
                >
                  Descripción
                </label>
                <textarea
                  value={form.desc || ''}
                  onChange={(e) =>
                    setForm((f) => ({ ...f, desc: e.target.value }))
                  }
                  placeholder="Ingredientes y descripción..."
                  style={{
                    width: '100%',
                    background: C.surface,
                    border: '1px solid #444',
                    borderRadius: 8,
                    color: C.white,
                    padding: '9px 12px',
                    fontSize: 14,
                    resize: 'vertical',
                    minHeight: 70,
                    fontFamily: 'inherit',
                  }}
                />
              </div>
              <InputField
                label="Precio (CLP) *"
                value={form.price || ''}
                onChange={(v) => setForm((f) => ({ ...f, price: v }))}
                placeholder="ej: 9990"
                type="number"
              />
              <div>
                <label
                  style={{
                    fontSize: 13,
                    color: C.gray,
                    display: 'block',
                    marginBottom: 4,
                  }}
                >
                  URL de imagen
                </label>
                <input
                  value={form.img || ''}
                  onChange={(e) =>
                    setForm((f) => ({ ...f, img: e.target.value }))
                  }
                  placeholder="https://... o pegar URL de imagen"
                  style={{
                    width: '100%',
                    background: C.surface,
                    border: '1px solid #444',
                    borderRadius: 8,
                    color: C.white,
                    padding: '9px 12px',
                    fontSize: 14,
                    fontFamily: 'inherit',
                  }}
                />
                {form.img && (
                  <img
                    src={form.img}
                    alt=""
                    style={{
                      width: '100%',
                      height: 140,
                      objectFit: 'cover',
                      borderRadius: 8,
                      marginTop: 8,
                    }}
                    onError={(e) => (e.target.style.display = 'none')}
                  />
                )}
              </div>
              <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                <label
                  style={{
                    fontSize: 14,
                    cursor: 'pointer',
                    display: 'flex',
                    alignItems: 'center',
                    gap: 8,
                  }}
                >
                  <input
                    type="checkbox"
                    checked={form.active !== false}
                    onChange={(e) =>
                      setForm((f) => ({ ...f, active: e.target.checked }))
                    }
                  />
                  Producto activo (visible en el menú)
                </label>
              </div>
            </div>
            <div style={{ display: 'flex', gap: 10, marginTop: 20 }}>
              <Btn
                onClick={saveProduct}
                disabled={!form.name || !form.price}
                style={{ flex: 1 }}
                color={C.green}
              >
                {editing ? '💾 Guardar cambios' : '✅ Crear producto'}
              </Btn>
              <Btn onClick={() => setShowForm(false)} color={C.grayLight}>
                Cancelar
              </Btn>
            </div>
          </div>
        </div>
      )}

      {/* Lista */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
        {filtered.map((p) => (
          <div
            key={p.id}
            style={{
              display: 'flex',
              gap: 12,
              background: C.card,
              borderRadius: 12,
              padding: 12,
              alignItems: 'center',
              opacity: p.active ? 1 : 0.5,
            }}
          >
            <img
              src={p.img}
              alt={p.name}
              style={{
                width: 60,
                height: 60,
                borderRadius: 8,
                objectFit: 'cover',
                flexShrink: 0,
              }}
              onError={(e) => {
                e.target.src =
                  'https://via.placeholder.com/60/2e2e2e/888?text=?';
              }}
            />
            <div style={{ flex: 1, minWidth: 0 }}>
              <div style={{ fontWeight: 700, fontSize: 15 }}>{p.name}</div>
              <div
                style={{
                  color: C.gray,
                  fontSize: 12,
                  overflow: 'hidden',
                  textOverflow: 'ellipsis',
                  whiteSpace: 'nowrap',
                }}
              >
                {p.desc}
              </div>
              <div
                style={{
                  display: 'flex',
                  gap: 8,
                  marginTop: 4,
                  alignItems: 'center',
                }}
              >
                <span style={{ color: C.gold, fontWeight: 800 }}>
                  {fmt(p.price)}
                </span>
                <span
                  style={{
                    background: '#333',
                    borderRadius: 4,
                    padding: '1px 8px',
                    fontSize: 11,
                    color: C.gray,
                  }}
                >
                  {CATS.find((c) => c.id === p.cat)?.label}
                </span>
                <span
                  style={{ fontSize: 11, color: p.active ? C.green : C.gray }}
                >
                  {p.active ? '● Activo' : '○ Oculto'}
                </span>
              </div>
            </div>
            <div style={{ display: 'flex', gap: 6, flexShrink: 0 }}>
              <button
                onClick={() => openEdit(p)}
                style={{
                  background: C.blue + '22',
                  border: `1px solid ${C.blue}`,
                  color: C.blue,
                  borderRadius: 6,
                  padding: '5px 10px',
                  cursor: 'pointer',
                  fontSize: 12,
                  fontWeight: 700,
                }}
              >
                ✏️
              </button>
              <button
                onClick={() => toggleActive(p.id)}
                style={{
                  background: '#33333344',
                  border: '1px solid #555',
                  color: C.gray,
                  borderRadius: 6,
                  padding: '5px 10px',
                  cursor: 'pointer',
                  fontSize: 12,
                }}
              >
                {p.active ? '🙈' : '👁️'}
              </button>
              <button
                onClick={() => deleteProduct(p.id)}
                style={{
                  background: C.red + '22',
                  border: `1px solid ${C.red}`,
                  color: C.red,
                  borderRadius: 6,
                  padding: '5px 10px',
                  cursor: 'pointer',
                  fontSize: 12,
                }}
              >
                🗑️
              </button>
            </div>
          </div>
        ))}
        {filtered.length === 0 && (
          <div style={{ textAlign: 'center', padding: 40, color: C.gray }}>
            No se encontraron productos
          </div>
        )}
      </div>
    </div>
  );
}

function CashRegister({ cashRegister, setCashRegister, orders }) {
  const [movForm, setMovForm] = useState({ type: 'in', amount: '', desc: '' });

  const openRegister = () => {
    const amount = parseFloat(
      prompt('Monto de apertura de caja (efectivo inicial):') || '0'
    );
    setCashRegister({
      open: true,
      openAmount: amount,
      movements: [],
      closedAt: null,
    });
  };

  const closeRegister = () => {
    if (!confirm('¿Cerrar caja? Se registrará el cierre actual.')) return;
    setCashRegister((prev) => ({ ...prev, open: false, closedAt: new Date() }));
  };

  const addMovement = () => {
    if (!movForm.amount || !movForm.desc) return;
    const mov = {
      type: movForm.type,
      amount: parseFloat(movForm.amount),
      desc: movForm.desc,
      at: new Date(),
    };
    setCashRegister((prev) => ({
      ...prev,
      movements: [...prev.movements, mov],
    }));
    setMovForm({ type: 'in', amount: '', desc: '' });
  };

  const cashIn = cashRegister.movements
    .filter((m) => m.type === 'in')
    .reduce((s, m) => s + m.amount, 0);
  const cashOut = cashRegister.movements
    .filter((m) => m.type === 'out')
    .reduce((s, m) => s + m.amount, 0);
  const balance = (cashRegister.openAmount || 0) + cashIn - cashOut;
  const deliveredOrders = orders.filter((o) => o.status === 'delivered');
  const salesByPayment = { efectivo: 0, transferencia: 0, link_pago: 0 };
  deliveredOrders.forEach((o) => {
    salesByPayment[o.payment] = (salesByPayment[o.payment] || 0) + o.total;
  });

  return (
    <div>
      {/* Estado caja */}
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: 12,
          marginBottom: 20,
          background: C.card,
          borderRadius: 14,
          padding: 16,
        }}
      >
        <div style={{ fontSize: 40 }}>{cashRegister.open ? '🟢' : '🔴'}</div>
        <div style={{ flex: 1 }}>
          <div style={{ fontWeight: 800, fontSize: 18 }}>
            Caja {cashRegister.open ? 'ABIERTA' : 'CERRADA'}
          </div>
          <div style={{ color: C.gray, fontSize: 13 }}>
            {cashRegister.open
              ? `Apertura: ${fmt(cashRegister.openAmount)}`
              : cashRegister.closedAt
              ? `Cerrada: ${new Date(cashRegister.closedAt).toLocaleString(
                  'es-CL'
                )}`
              : 'Caja sin abrir'}
          </div>
        </div>
        {!cashRegister.open ? (
          <Btn onClick={openRegister} color={C.green}>
            Abrir caja
          </Btn>
        ) : (
          <Btn onClick={closeRegister} color={C.red}>
            Cerrar caja
          </Btn>
        )}
      </div>

      {/* Resumen */}
      <div
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(140px, 1fr))',
          gap: 10,
          marginBottom: 20,
        }}
      >
        <StatCard
          label="Monto apertura"
          value={fmt(cashRegister.openAmount || 0)}
          color={C.gray}
        />
        <StatCard label="Ingresos" value={fmt(cashIn)} color={C.green} />
        <StatCard label="Egresos" value={fmt(cashOut)} color={C.red} />
        <StatCard label="Balance caja" value={fmt(balance)} color={C.gold} />
        <StatCard
          label="Ventas pedidos"
          value={fmt(deliveredOrders.reduce((s, o) => s + o.total, 0))}
          color={C.blue}
        />
      </div>

      {/* Ventas por método de pago */}
      <div
        style={{
          background: C.card,
          borderRadius: 12,
          padding: 16,
          marginBottom: 20,
        }}
      >
        <div style={{ fontWeight: 700, marginBottom: 12, color: C.gold }}>
          💳 Ventas por método de pago
        </div>
        {Object.entries(salesByPayment).map(([key, val]) => (
          <div
            key={key}
            style={{
              display: 'flex',
              justifyContent: 'space-between',
              padding: '6px 0',
              borderBottom: '1px solid #333',
              fontSize: 14,
            }}
          >
            <span style={{ color: C.gray }}>
              {key === 'efectivo'
                ? '💵 Efectivo'
                : key === 'transferencia'
                ? '🏦 Transferencia'
                : '🔗 Link de pago'}
            </span>
            <span style={{ fontWeight: 700, color: C.white }}>{fmt(val)}</span>
          </div>
        ))}
      </div>

      {/* Ingresar movimiento */}
      {cashRegister.open && (
        <div
          style={{
            background: C.card,
            borderRadius: 12,
            padding: 16,
            marginBottom: 20,
          }}
        >
          <div style={{ fontWeight: 700, marginBottom: 12 }}>
            Registrar movimiento de caja
          </div>
          <div
            style={{
              display: 'grid',
              gridTemplateColumns: 'auto 1fr 1fr auto',
              gap: 8,
              alignItems: 'end',
            }}
          >
            <div>
              <label
                style={{
                  fontSize: 12,
                  color: C.gray,
                  display: 'block',
                  marginBottom: 4,
                }}
              >
                Tipo
              </label>
              <select
                value={movForm.type}
                onChange={(e) =>
                  setMovForm((f) => ({ ...f, type: e.target.value }))
                }
                style={{
                  background: C.surface,
                  border: '1px solid #444',
                  borderRadius: 8,
                  padding: '8px',
                  color: C.white,
                  fontFamily: 'inherit',
                }}
              >
                <option value="in">+ Ingreso</option>
                <option value="out">− Egreso</option>
              </select>
            </div>
            <InputField
              label="Monto"
              value={movForm.amount}
              onChange={(v) => setMovForm((f) => ({ ...f, amount: v }))}
              placeholder="$"
              type="number"
            />
            <InputField
              label="Descripción"
              value={movForm.desc}
              onChange={(v) => setMovForm((f) => ({ ...f, desc: v }))}
              placeholder="Concepto..."
            />
            <Btn
              onClick={addMovement}
              disabled={!movForm.amount || !movForm.desc}
              color={movForm.type === 'in' ? C.green : C.red}
              style={{ alignSelf: 'flex-end' }}
            >
              Agregar
            </Btn>
          </div>
        </div>
      )}

      {/* Movimientos */}
      {cashRegister.movements.length > 0 && (
        <div style={{ background: C.card, borderRadius: 12, padding: 16 }}>
          <div style={{ fontWeight: 700, marginBottom: 12 }}>Movimientos</div>
          {[...cashRegister.movements].reverse().map((m, i) => (
            <div
              key={i}
              style={{
                display: 'flex',
                justifyContent: 'space-between',
                padding: '8px 0',
                borderBottom: '1px solid #333',
                fontSize: 14,
              }}
            >
              <div>
                <span style={{ marginRight: 8 }}>
                  {m.type === 'in' ? '↑' : '↓'}
                </span>
                <span style={{ color: C.gray }}>{m.desc}</span>
                <span style={{ color: C.gray, fontSize: 12, marginLeft: 8 }}>
                  {new Date(m.at).toLocaleTimeString('es-CL', {
                    hour: '2-digit',
                    minute: '2-digit',
                  })}
                </span>
              </div>
              <span
                style={{
                  fontWeight: 700,
                  color: m.type === 'in' ? C.green : C.red,
                }}
              >
                {m.type === 'in' ? '+' : '−'}
                {fmt(m.amount)}
              </span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

function StatsView({ orders, menu }) {
  const delivered = orders.filter((o) => o.status === 'delivered');
  const totalSales = delivered.reduce((s, o) => s + o.total, 0);
  const avgOrder = delivered.length > 0 ? totalSales / delivered.length : 0;

  // Top productos
  const productCounts = {};
  delivered.forEach((o) =>
    o.items?.forEach((i) => {
      productCounts[i.name] = (productCounts[i.name] || 0) + i.qty;
    })
  );
  const topProducts = Object.entries(productCounts)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 5);

  // Por delivery vs pickup
  const deliveryCount = delivered.filter(
    (o) => o.delivery === 'delivery'
  ).length;
  const pickupCount = delivered.filter((o) => o.delivery === 'pickup').length;

  return (
    <div>
      <div
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(150px, 1fr))',
          gap: 10,
          marginBottom: 20,
        }}
      >
        <StatCard label="Total ventas" value={fmt(totalSales)} color={C.gold} />
        <StatCard
          label="Pedidos entregados"
          value={delivered.length}
          color={C.green}
        />
        <StatCard
          label="Ticket promedio"
          value={fmt(Math.round(avgOrder))}
          color={C.blue}
        />
        <StatCard
          label="Pedidos totales"
          value={orders.length}
          color={C.gray}
        />
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
        <div style={{ background: C.card, borderRadius: 12, padding: 16 }}>
          <div style={{ fontWeight: 700, marginBottom: 12, color: C.gold }}>
            🏆 Top productos
          </div>
          {topProducts.length === 0 ? (
            <div style={{ color: C.gray, fontSize: 13 }}>Sin datos aún</div>
          ) : (
            topProducts.map(([name, qty], i) => (
              <div
                key={name}
                style={{
                  display: 'flex',
                  justifyContent: 'space-between',
                  padding: '6px 0',
                  borderBottom: '1px solid #333',
                  fontSize: 14,
                }}
              >
                <span style={{ color: C.gray }}>
                  {i + 1}. {name}
                </span>
                <span style={{ fontWeight: 700 }}>{qty} uds.</span>
              </div>
            ))
          )}
        </div>
        <div style={{ background: C.card, borderRadius: 12, padding: 16 }}>
          <div style={{ fontWeight: 700, marginBottom: 12, color: C.gold }}>
            🚗 Tipo de entrega
          </div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between' }}>
              <span style={{ color: C.gray }}>🚗 Delivery</span>
              <span style={{ fontWeight: 700 }}>{deliveryCount}</span>
            </div>
            <div style={{ display: 'flex', justifyContent: 'space-between' }}>
              <span style={{ color: C.gray }}>🏃 Retiro</span>
              <span style={{ fontWeight: 700 }}>{pickupCount}</span>
            </div>
            <div style={{ display: 'flex', justifyContent: 'space-between' }}>
              <span style={{ color: C.gray }}>📦 Total</span>
              <span style={{ fontWeight: 700, color: C.gold }}>
                {delivered.length}
              </span>
            </div>
          </div>
          <div
            style={{
              fontWeight: 700,
              marginTop: 16,
              marginBottom: 12,
              color: C.gold,
            }}
          >
            💳 Métodos de pago
          </div>
          {['efectivo', 'transferencia', 'link_pago'].map((pm) => {
            const count = delivered.filter((o) => o.payment === pm).length;
            return (
              <div
                key={pm}
                style={{
                  display: 'flex',
                  justifyContent: 'space-between',
                  fontSize: 14,
                  marginBottom: 6,
                }}
              >
                <span style={{ color: C.gray }}>
                  {pm === 'efectivo'
                    ? '💵 Efectivo'
                    : pm === 'transferencia'
                    ? '🏦 Transferencia'
                    : '🔗 Link pago'}
                </span>
                <span style={{ fontWeight: 700 }}>{count}</span>
              </div>
            );
          })}
        </div>
      </div>

      {/* Últimos pedidos */}
      <div
        style={{
          background: C.card,
          borderRadius: 12,
          padding: 16,
          marginTop: 16,
        }}
      >
        <div style={{ fontWeight: 700, marginBottom: 12, color: C.gold }}>
          📋 Últimos pedidos
        </div>
        {orders.slice(0, 8).map((o) => (
          <div
            key={o.id}
            style={{
              display: 'flex',
              justifyContent: 'space-between',
              padding: '8px 0',
              borderBottom: '1px solid #333',
              fontSize: 13,
            }}
          >
            <div>
              <span style={{ fontWeight: 700 }}>
                #{o.id?.toString().slice(-4)}
              </span>
              <span style={{ color: C.gray, marginLeft: 8 }}>
                {o.customerName}
              </span>
              <span style={{ color: C.gray, marginLeft: 8, fontSize: 12 }}>
                {new Date(o.createdAt).toLocaleTimeString('es-CL', {
                  hour: '2-digit',
                  minute: '2-digit',
                })}
              </span>
            </div>
            <div style={{ textAlign: 'right' }}>
              <span style={{ color: C.gold, fontWeight: 700 }}>
                {fmt(o.total)}
              </span>
              <span
                style={{
                  marginLeft: 8,
                  fontSize: 11,
                  color: {
                    pending: '#e67e22',
                    preparing: C.blue,
                    ready: C.green,
                    delivered: C.gray,
                    cancelled: C.red,
                  }[o.status],
                }}
              >
                {o.status}
              </span>
            </div>
          </div>
        ))}
        {orders.length === 0 && (
          <div style={{ color: C.gray, fontSize: 13 }}>
            No hay pedidos registrados
          </div>
        )}
      </div>
    </div>
  );
}

// ─── COMPONENTES UTILITARIOS ──────────────────────────────────────────────────
function Section({ title, children }) {
  return (
    <div style={{ marginBottom: 20 }}>
      <div
        style={{
          fontWeight: 700,
          fontSize: 14,
          color: C.gold,
          marginBottom: 10,
          textTransform: 'uppercase',
          letterSpacing: 1,
        }}
      >
        {title}
      </div>
      <div style={{ background: C.surface, borderRadius: 12, padding: 14 }}>
        {children}
      </div>
    </div>
  );
}

function InputField({
  label,
  value,
  onChange,
  placeholder,
  type = 'text',
  style = {},
}) {
  return (
    <div style={style}>
      {label && (
        <label
          style={{
            fontSize: 13,
            color: C.gray,
            display: 'block',
            marginBottom: 4,
          }}
        >
          {label}
        </label>
      )}
      <input
        type={type}
        value={value}
        onChange={(e) => onChange(e.target.value)}
        placeholder={placeholder}
        style={{
          width: '100%',
          background: C.card,
          border: '1px solid #444',
          borderRadius: 8,
          padding: '9px 12px',
          color: C.white,
          fontSize: 14,
          fontFamily: 'inherit',
        }}
      />
    </div>
  );
}

function StatCard({ label, value, color }) {
  return (
    <div
      style={{
        background: C.card,
        borderRadius: 10,
        padding: '12px 14px',
        textAlign: 'center',
      }}
    >
      <div style={{ color, fontWeight: 900, fontSize: 22 }}>{value}</div>
      <div style={{ color: C.gray, fontSize: 12, marginTop: 4 }}>{label}</div>
    </div>
  );
}
